import { useEffect, useState } from "react";

const SIZE = 10;

function point(x, y) {
  return { x, y };
}

function add(a, b) {
  return point(a.x + b.x, a.y + b.y);
}

function equal(a, b) {
  return a.x === b.x && a.y === b.y;
}

function randomFood(snake) {
  while (true) {
    const food = point(
      Math.floor(Math.random() * SIZE),
      Math.floor(Math.random() * SIZE)
    );

    if (!snake.some(part => equal(part, food))) {
      return food;
    }
  }
}

export default function Snake() {
  const [snake, setSnake] = useState([
    point(5, 5),
  ]);

  const [food, setFood] = useState(
    point(2, 2)
  );

  const [direction, setDirection] = useState(
    point(1, 0)
  );

  useEffect(() => {
    const timer = setInterval(() => {
      setSnake(snake => {
        const head = add(
          snake[0],
          direction
        );

        const nextSnake = [
          head,
          ...snake,
        ];

        if (equal(head, food)) {
          setFood(randomFood(nextSnake));
          return nextSnake;
        }

        nextSnake.pop();

        return nextSnake;
      });
    }, 300);

    return () => clearInterval(timer);
  }, [direction, food]);

  function keyDown(e) {
    if (e.key === "ArrowUp") {
      setDirection(point(0, -1));
    }

    if (e.key === "ArrowDown") {
      setDirection(point(0, 1));
    }

    if (e.key === "ArrowLeft") {
      setDirection(point(-1, 0));
    }

    if (e.key === "ArrowRight") {
      setDirection(point(1, 0));
    }
  }

  function color(cell) {
    if (snake.some(part => equal(part, cell))) {
      return "green";
    }

    if (equal(food, cell)) {
      return "red";
    }

    return "white";
  }

  return (
    <main
      onKeyDown={keyDown}
      tabIndex={0}
      autoFocus
    >
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {Array.from({ length: SIZE }, (_, y) => (
            <tr key={y}>
              {Array.from({ length: SIZE }, (_, x) => (
                <td
                  key={x}
                  style={{
                    width: 25,
                    height: 25,
                    border: "1px solid",
                    background: color(point(x, y)),
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
